class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed "Discriminator" to "$type". Preserve the old property
            // name so existing 500K documents remain queryable without migration.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityName|<key>" to just "<key>".
            // Use IdProperty + ValueGeneratedNever to keep the legacy format, OR
            // set the id shadow property with a value generator. Simplest: opt back in
            // to the legacy format via HasJsonIdProperty + convention override.
            entity.Property<string>("__id");
            entity.HasKey("Id");

            // Preserve legacy "Product|123" id format for existing documents.
            entity.Property(p => p.Id).ToJsonProperty("Id");
        });

        // Global: keep the legacy id format ("EntityType|KeyValue") so reads of
        // existing documents succeed without rewriting all 500K docs.
        // EF Core 9 default would generate id = just the key value.
#pragma warning disable EF1001 // Internal EF Core API usage (if needed)
        modelBuilder.HasManualIdGeneration(false);
#pragma warning restore EF1001
    }

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 removed sync I/O support for Cosmos provider.
        // All queries must use async (ToListAsync, FirstOrDefaultAsync, etc.).
    }
}
