{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 renamed the discriminator property
            // from "Discriminator" to "$type". Existing documents have "Discriminator".
            // This preserves the old name so existing docs and raw SQL queries still work.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // BREAKING CHANGE 2: EF Core 9 changed the id format.
            // EF8: "Product|123"  →  EF9 default: "123"
